import{_ as r,o as t,c as a,a5 as o}from"./chunks/framework.BsG5PWQ9.js";const u=JSON.parse('{"title":"Service provider","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/personas/service-provider.md","filePath":"concepts/personas/service-provider.md"}'),i={name:"concepts/personas/service-provider.md"};function n(s,e,l,h,c,d){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="service-provider" tabindex="-1">Service provider <a class="header-anchor" href="#service-provider" aria-label="Permalink to &quot;Service provider&quot;">​</a></h1><p>Service providers build and operate services that can be consumed through Platform Mesh. They define the declarative API contract for a capability and own the automation that turns consumer intent into real service instances.</p><p>Provider examples include teams offering databases, certificates, CI/CD pipelines, AI infrastructure, or internal platform services.</p><h2 id="goal" tabindex="-1">Goal <a class="header-anchor" href="#goal" aria-label="Permalink to &quot;Goal&quot;">​</a></h2><p>Expose a service capability through a stable API while keeping implementation details, runtime topology, and provider operations behind the provider boundary.</p><h2 id="responsibilities" tabindex="-1">Responsibilities <a class="header-anchor" href="#responsibilities" aria-label="Permalink to &quot;Responsibilities&quot;">​</a></h2><ul><li>Define the service API consumers use to request and manage capabilities.</li><li>Publish that API through Platform Mesh so consumers can discover and bind it.</li><li>Reconcile consumer desired state into provider-owned runtime resources.</li><li>Report lifecycle status back to consumers.</li><li>Choose the right integration path for the provider&#39;s API and controller model.</li></ul><h2 id="ownership-boundary" tabindex="-1">Ownership boundary <a class="header-anchor" href="#ownership-boundary" aria-label="Permalink to &quot;Ownership boundary&quot;">​</a></h2><p>The provider owns <strong>what</strong> can be ordered (the API schema) and <strong>how</strong> it gets fulfilled (the controller logic). They do not own the consumer&#39;s workspace, the consumer&#39;s resources, or the platform runtime. The API contract is the only surface visible across that boundary; everything behind it — clusters, VMs, SaaS calls, internal databases — stays inside the provider.</p><p>This separation keeps the lifecycle API consistent even when the underlying implementation changes. A provider can migrate from self-hosted infrastructure to a managed cloud service without breaking consumer workflows.</p><h2 id="common-questions" tabindex="-1">Common questions <a class="header-anchor" href="#common-questions" aria-label="Permalink to &quot;Common questions&quot;">​</a></h2><ul><li>Should this provider use api-syncagent or multi-cluster-runtime?</li><li>Which CRDs or APIs should be exposed to consumers?</li><li>How does consumer desired state reach the provider runtime?</li><li>How does provider status flow back to the consumer workspace?</li><li>How can one provider consume another provider&#39;s API?</li></ul><h2 id="recommended-reading" tabindex="-1">Recommended reading <a class="header-anchor" href="#recommended-reading" aria-label="Permalink to &quot;Recommended reading&quot;">​</a></h2><p>Start with <a href="./../integration-paths.html">Integration paths</a> to choose a mechanism, then read <a href="./../integration/api-syncagent.html">api-syncagent</a> or <a href="./../integration/multi-cluster-runtime.html">multi-cluster-runtime</a> depending on the provider model. Use <a href="./../interaction-patterns/provider-to-consumer.html">Interaction patterns</a> to understand provider-to-consumer and provider-to-provider flows, and <a href="./../api-sharing.html">API sharing</a> for the contract between provider and consumer workspaces.</p><p>When you are ready for hands-on work, follow the <a href="/pr-preview/pr-138/tutorials/provider-quick-start.html">Provider quick start</a> tutorial for the api-syncagent path, then <a href="/pr-preview/pr-138/tutorials/build-multi-cluster-runtime-provider.html">Build a multi-cluster-runtime provider</a> for the custom-controller path.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./">Personas overview</a></li><li><a href="./platform-owner.html">Platform owner</a> — the role that onboards providers</li><li><a href="./service-consumer.html">Service consumer</a> — the role on the other side of the API contract</li><li><a href="./../integration-paths.html">Integration paths</a></li><li><a href="./../api-sharing.html">API sharing</a></li></ul>',17)])])}const m=r(i,[["render",n]]);export{u as __pageData,m as default};
